SELECT file_name, file_size
FROM file_search
WHERE is_indexed = 1;

SELECT name, modified_at, modified_by
FROM file_system_entities
ORDER BY modified_at DESC;

SELECT COUNT(*) AS file_count
FROM files
WHERE modified_at > '2023-09-01 00:00:00';

SELECT file_id, MAX(created_at) AS latest_version_time, created_by
FROM file_versions
GROUP BY file_id;

SELECT created_by, COUNT(*) AS entity_count
FROM file_system_entities
GROUP BY created_by;

SELECT name
FROM file_system_entities
WHERE created_by = 1 AND modified_by = 1 AND is_file = 1;
